# Homebrew formula for cc-pool. Installs the prebuilt universal binary from
# GitHub Releases — no Go toolchain needed. `brew install --HEAD` builds from
# source instead.
#
#   brew install yasyf/tap/cc-pool
#
# One prebuilt pure-Go universal binary (arm64 + amd64) ships per release.
#
# This file is GENERATED by cc-pool's release.yml (render-formula) and
# pushed here on every tagged release — do not hand-edit; change the
# template at .github/formula/cc-pool.rb.tmpl in cc-pool instead.
class CcPool < Formula
  desc "Predictive multi-account load-balancing for Claude Code"
  homepage "https://github.com/yasyf/cc-pool"
  url "https://github.com/yasyf/cc-pool/releases/download/v0.61.1/cc-pool-v0.61.1-darwin-universal.tar.gz"
  sha256 "d1891a2b058a353dc1609eacd99586bdafb3141d496e1fa8d929d878a387a62d" # pure
  license "PolyForm-Noncommercial-1.0.0"

  livecheck do
    url :stable
    strategy :github_latest
  end

  head do
    url "https://github.com/yasyf/cc-pool.git", branch: "main"
    depends_on "go" => :build
  end

  depends_on :macos

  def install
    if build.head?
      install_from_source
    else
      bin.install "cc-pool"
    end
    bin.install_symlink "cc-pool" => "ccp"
  end

  # HEAD builds compile pure Go from source.
  def install_from_source
    ldflags = %W[
      -s -w
      -X github.com/yasyf/cc-pool/internal/version.Version=#{version}
    ]
    args = std_go_args(ldflags: ldflags.join(" "), output: bin/"cc-pool")
    ENV["CGO_ENABLED"] = "0"
    system "go", "build", *args, "./cmd/cc-pool"
  end

  def caveats
    <<~EOS
      Get started:
        ccp             # walks you through pooling your subscriptions
        ccp run         # launch claude on the emptiest account

      The daemon requires the fixed signed status/File Provider/holder app.
      Install the complete stack with:
        brew install --cask yasyf/tap/cc-pool-status
        ccp service install

      daemonkit owns the user LaunchAgent. Homebrew does not install or control
      a second daemon service, and a formula-only install cannot start one.

      Plain `claude` on ~/.claude keeps working untouched.

      Before `brew uninstall`, run `ccp service uninstall` to stop the daemon
      and stop active pool sessions.
    EOS
  end

  test do
    assert_match version.to_s, shell_output("#{bin}/cc-pool --version")
    assert_match "emptiest account", shell_output("#{bin}/ccp --help")
  end
end
